<?php
namespace Tests\Feature;
use App\Models\User;use App\Services\ExamService;use App\Services\IdCodec;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Symfony\Component\HttpKernel\Exception\HttpException;use Tests\TestCase;
class SecurityRegressionTest extends TestCase {use RefreshDatabase;protected bool $seed=true;public function test_api_heartbeat_rejects_another_students_session():void{$id=app(IdCodec::class)->encode(1);$token=$this->postJson('/api/v1/auth/login',['username'=>'siswa','password'=>'siswa123'])->json('data.token');$this->withHeaders(['Authorization'=>'Bearer '.$token])->postJson("/api/v1/ujian/$id/masuk",['token'=>'LATIHAN'])->assertOk();DB::table('users')->insert(['username'=>'siswa2','name'=>'Siswa Dua','email'=>'siswa2@cbt.local','password'=>bcrypt('siswa2123'),'role'=>'Siswa','kelas_aktif_id'=>1,'status_kehadiran'=>'hadir','created_at'=>now(),'updated_at'=>now()]);$token2=$this->postJson('/api/v1/auth/login',['username'=>'siswa2','password'=>'siswa2123'])->json('data.token');$this->withHeaders(['Authorization'=>'Bearer '.$token2])->postJson("/api/v1/ujian/sesi/$id/ping")->assertForbidden();}public function test_exam_service_rejects_option_from_another_question():void{$service=app(ExamService::class);$session=$service->start(User::where('username','siswa')->first(),1,'LATIHAN','127.0.0.1','phpunit');$questions=DB::table('bank_soals')->orderBy('id')->get();$foreignOption=DB::table('opsi_jawabans')->where('bank_soal_id',$questions[1]->id)->value('id');$this->expectException(HttpException::class);$service->save($session,$questions[0]->id,$foreignOption,null);}public function test_api_validation_errors_use_standard_wrapper():void{$this->postJson('/api/v1/auth/login',[])->assertStatus(422)->assertJsonPath('success',false)->assertJsonStructure(['data','message','error','code','details']);}public function test_scheduled_result_stays_hidden_until_release_time():void{$id=app(IdCodec::class)->encode(1);$this->post('/login',['username'=>'siswa','password'=>'siswa123'])->assertRedirectContains('/dashboard?auth_refresh=');$this->post("/ujian/$id/mulai",['token'=>'LATIHAN'])->assertRedirect("/ujian/sesi/$id?nomor=1");$this->post("/ujian/sesi/$id/selesai")->assertRedirect("/ujian/sesi/$id/hasil");DB::table('master_ujians')->where('id',1)->update(['hasil_visibilitas'=>'scheduled','tampilkan_nilai_akhir'=>true,'tanggal_rilis_hasil'=>now()->addHour()]);$this->get("/ujian/sesi/$id/hasil")->assertOk()->assertSee('Nilai belum dirilis');DB::table('master_ujians')->where('id',1)->update(['tanggal_rilis_hasil'=>now()->subHour()]);$this->get("/ujian/sesi/$id/hasil")->assertOk()->assertSee('Nilai akhir');}}